mapper.update:
UPDATE chat_message SET status = #{status}, updated_at = NOW()
WHERE id IN

    #{id}

mapper.select:
SELECT m.*, u.username as sender_username, u.avatar as sender_avatar, rm.content as reply_content, rm.type as reply_type, ru.username as reply_sender_username FROM chat_message m JOIN user u ON m.sender_id = u.id LEFT JOIN chat_message rm ON m.reply_to_message_id = rm.id LEFT JOIN user ru ON rm.sender_id = ru.id WHERE
m.group_id = #{groupId}
((m.sender_id = #{userId} AND m.receiver_id = #{friendId}) OR (m.sender_id = #{friendId} AND m.receiver_id = #{userId})) AND m.group_id IS NULL
ORDER BY m.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT m.*, u.username as sender_username, u.avatar as sender_avatar, rm.content as reply_content, rm.type as reply_type, ru.username as reply_sender_username FROM chat_message m JOIN user u ON m.sender_id = u.id LEFT JOIN chat_message rm ON m.reply_to_message_id = rm.id LEFT JOIN user ru ON rm.sender_id = ru.id WHERE
m.group_id = #{groupId}
((m.sender_id = #{userId} AND m.receiver_id = #{friendId}) OR (m.sender_id = #{friendId} AND m.receiver_id = #{userId})) AND m.group_id IS NULL
AND (m.id > #{lastMessageId}
OR m.updated_at > #{lastSyncTime}
) ORDER BY m.created_at ASC

mapper.delete:
DELETE m FROM chat_message m
JOIN chat_group g ON m.group_id = g.id
WHERE g.owner_id = #{ownerId}
